-- migrate:up

-- Bulk demo dataset (ops/viewer users, ~240 mock merchants, demo memberships).
-- Gated: the migrate service sets `app.seed_demo = off` in production
-- (PGOPTIONS=-c app.seed_demo=off), so a fresh prod DB never gets the mock data.
-- Unset (dev/test) leaves it enabled.
DO $$
BEGIN
  IF current_setting('app.seed_demo', true) IS DISTINCT FROM 'off' THEN


    -- Refresh deterministic credentials for the merchants just inserted.
    UPDATE merchants SET
      mpesa_consumer_key    = CONCAT('mpesa_ck_', mpesa_paybill_number),
      mpesa_consumer_secret = CONCAT('mpesa_cs_', mpesa_paybill_number),
      sasapay_client_id     = CONCAT('sasapay_cid_', sasapay_till_number),
      sasapay_client_secret = CONCAT('sasapay_cs_', sasapay_till_number);

    -- Ops owns two tills + co-admins a third; Viewer is read-only on the first.
  END IF;
END $$;

-- migrate:down

DELETE FROM merchants
WHERE (mpesa_paybill_number ~ '^(884|885|886|887)[0-9]{3}$'
   OR sasapay_till_number ~ '^888[0-9]{3}$')
  AND mpesa_paybill_number NOT IN ('887000', '887001', '887002', '887003', '887004', '887005', '887006', '887007', '887008', '887009');
DELETE FROM users WHERE email IN ('ops@noria.co.ke', 'viewer@noria.co.ke');
